from flow_autotts.controllers.optimal import OptimalController

class P:
    def __init__(self, pid, time=0.0, status='active', last_preview_id=None):
        self.id=pid; self.time=time; self.status=status; self.last_preview_id=last_preview_id

class Prev:
    def __init__(self, pid, particle_id, score, uncertainty=0.1, time=0.2):
        self.id=pid; self.particle_id=particle_id; self.score=score; self.uncertainty=uncertainty; self.time=time

class State:
    def __init__(self, particles, previews):
        self.particles=particles; self.previews=previews

class Env:
    def __init__(self):
        self.time_grid=(0.0,0.25,0.5,0.75,1.0)
        self.budget=50
        self.budget_left=50
        self._next=0
        self._particles={}
        self._previews={}
    def get_state(self):
        return State(dict(self._particles), dict(self._previews))
    def spawn(self,n):
        out=[]
        for _ in range(n):
            pid=self._next; self._next+=1; out.append(pid); self._particles[pid]=P(pid)
        return out
    def forward(self, particle_id, target_time, solver='euler', cfg=None):
        p=self._particles[particle_id]; p.time=target_time
        self.budget_left-=1
        if target_time>=1.0: p.status='completed'
        return p
    def preview(self, particle_id, mode='clean_anchor', scorer='default'):
        pid=len(self._previews)
        p=self._particles[particle_id]
        p.last_preview_id=pid
        self._previews[pid]=Prev(pid, particle_id, score=float(particle_id)+p.time, uncertainty=0.1, time=p.time)
        self.budget_left-=1
        return self._previews[pid]
    def backward(self, anchor_id, target_time, noise_policy='fresh_noise', num_children=1, mask=None, strength=1.0):
        out=[]
        for _ in range(num_children):
            pid=self._next; self._next+=1; out.append(pid); self._particles[pid]=P(pid, time=target_time)
        return out
    def prune(self, particle_ids):
        for pid in particle_ids:
            self._particles[pid].status='pruned'
    def answer(self, rule='best_preview_score'):
        return SimpleNamespace(rule=rule, nfe_used=self.budget-self.budget_left)

